sql:
SELECT COUNT(criterion_id) AS total_criteria
FROM session_criteria
WHERE session_id = 0;

SELECT criterion_id, AVG(rating) AS average_rating
FROM session_evaluations
GROUP BY criterion_id;

SELECT AVG(rating) AS average_rating
FROM session_evaluations
WHERE session_id = 0;

external_knowledge:
; The term "top-rated" refers to those with the highest average ratings; 
; Presenters are ranked based on their overall performance, taking into account multiple sessions and evaluation criteria; 
; The evaluation criteria and their corresponding ratings are used to assess the presenter's performance.

sql:
SELECT MAX(rating) AS highest_rating
FROM session_evaluations
WHERE criterion_id = 1;

SELECT session_id, COUNT(attendee_id) AS number_of_attendees
FROM session_attendees
GROUP BY session_id;
